import React from "react";
import styles from "./cart-item.module.css";
import CartLayout from "../../layout/cart-layout";

const CartItem = () => {
  return (
    <div className={styles.wrapper_cart_item}>
      <CartLayout>
        <div className={styles.cart_product}>
            <img src="/images/candle-1.svg" alt="candle" width={160} height={120} />
        </div>
        <div className={styles.cart_price}>

        </div>
        <div className={styles.cart_quantity}></div>
        <div className={styles.cart_total}></div>
      </CartLayout>
    </div>
  );
};

export default CartItem;
